#include <bits/stdc++.h>
using namespace std;

const int mod=1e9+7;

int T,n;
int ans[3][3],base[3][3],tmp[3][3];

int main(){
    scanf("%d",&T);
    while(T--){
        scanf("%d",&n);
        for(int i=0;i<3;i++)
            for(int j=0;j<3;j++){
                ans[i][j]=(i==j);
                base[i][j]=0;
            }
        base[1][0]=base[2][1]=base[0][2]=base[2][2]=1;
        n-=1;
        while(n){
            if(n&1){
                for(int i=0;i<3;i++)
                    for(int j=0;j<3;j++){
                        tmp[i][j]=0;
                        for(int k=0;k<3;k++)
                            tmp[i][j]=(tmp[i][j]+1ll*ans[i][k]*base[k][j])%mod;
                    }
                for(int i=0;i<3;i++)
                    for(int j=0;j<3;j++)
                        ans[i][j]=tmp[i][j];
            }
            for(int i=0;i<3;i++)
                for(int j=0;j<3;j++){
                    tmp[i][j]=0;
                    for(int k=0;k<3;k++)
                        tmp[i][j]=(tmp[i][j]+1ll*base[i][k]*base[k][j])%mod;
                }
            for(int i=0;i<3;i++)
                for(int j=0;j<3;j++)
                    base[i][j]=tmp[i][j];
            n>>=1;
        }
        printf("%d\n",((long long)ans[0][0]+ans[1][0]+ans[2][0])%mod);
    }
    return 0;
}
